import {
  DndContext,
  closestCenter,
  DragOverlay,
  MeasuringStrategy,
} from "@dnd-kit/core";
import { restrictToWindowEdges } from "@dnd-kit/modifiers";

import { FieldPlaceholder } from "../../common";

import { useSchemaFormViewDnd } from "./hooks";
import { SchemaEditZone } from "./zone";

import type { SchemaViewType } from "@/components/fsui/fscommon";

export const SchemaFormViewDnd = <
  TView extends SchemaViewType<Record<string, string>>,
>({
  view,
}: {
  view: TView;
}) => {
  type ZoneKeys = keyof typeof view.zones;

  const { sensors, activeField, onDragStart, onDragOver, onDragEnd } =
    useSchemaFormViewDnd({ view });

  const zones = {} as Record<ZoneKeys, React.ReactNode>;
  for (const zoneId in view.zones) {
    if (Object.prototype.hasOwnProperty.call(view.zones, zoneId)) {
      zones[zoneId] = (
        <SchemaEditZone
          key={zoneId}
          zoneId={zoneId}
          view={view}
        />
      );
    }
  }

  if (!view) {
    return <div>No view selected.</div>;
  }

  return (
    <DndContext
      sensors={sensors}
      collisionDetection={closestCenter}
      modifiers={[restrictToWindowEdges]}
      onDragStart={onDragStart}
      onDragOver={onDragOver}
      onDragEnd={onDragEnd}
      measuring={{
        droppable: {
          strategy: MeasuringStrategy.Always,
        },
      }}
    >
      {view.render({ zones })}
      <DragOverlay adjustScale={false}>
        {activeField && (
          <FieldPlaceholder
            id={activeField.name}
            field={activeField}
            opacity={0.9}
          />
        )}
      </DragOverlay>
    </DndContext>
  );
};

import { useSortable } from "@dnd-kit/sortable";
import { CSS } from "@dnd-kit/utilities";
import { Eye, EyeOff, GripVertical, Pencil, Trash2 } from "lucide-react";

import { Button } from "@/components/ui/button";
import {
  Item,
  ItemActions,
  ItemContent,
  ItemMedia,
  ItemTitle,
} from "@/components/ui/item";
import {
  Tooltip,
  TooltipContent,
  TooltipTrigger,
} from "@/components/ui/tooltip";
import { cn } from "@/lib/utils";
import { ButtonTooltip } from "@/components/fsui/fscommon/button-tooltip";
import { PopConfirm } from "@/components/fsui/fscommon/pop-confirm";

import { fieldTypesInfo } from "../../common";
import { editingFieldStore } from "../../store";

import type { FieldDefinition, ZoneFieldSettings } from "fastschema";

export const SchemaFormFieldHandle = ({
  field,
  zoneFieldSettings,
  hiddenFields = [],
  setFieldHidden,
  removeField,
}: {
  field: FieldDefinition;
  zoneFieldSettings?: ZoneFieldSettings;
  hiddenFields?: string[];
  setFieldHidden?: (fieldName: string, hidden: boolean) => void;
  removeField?: (fieldName: string) => void;
}) => {
  const {
    attributes,
    listeners,
    setNodeRef,
    transform,
    transition,
    isDragging,
  } = useSortable({
    id: field.name,
    data: { field, zoneFieldSettings },
  });

  const style = {
    transform: CSS.Transform.toString(transform),
    transition,
    opacity: isDragging ? 0.9 : 1,
  };

  const Icon = fieldTypesInfo[field.type]?.icon;
  const isHidden = hiddenFields.includes(field.name);
  return (
    <div
      ref={setNodeRef}
      style={style}
      {...attributes}
    >
      <Item
        variant="outline"
        size="sm"
        className={cn(
          "border-0 bg-white p-2",
          isDragging && "bg-yellow-100 shadow-lg",
        )}
        style={{
          boxShadow:
            "0 0 #0000, 0 0 #0000, 0px 2px 4px 0px rgba(0, 0, 0, 0.14), 0px 0px 2px 0px rgba(0, 0, 0, 0.12)",
        }}
      >
        <ItemMedia className="pl-1">
          <Tooltip>
            <TooltipTrigger>
              <Icon className="size-5" />
            </TooltipTrigger>
            <TooltipContent>
              <p>{field.type}</p>
            </TooltipContent>
          </Tooltip>
        </ItemMedia>
        <ItemContent>
          <ItemTitle>{field.label}</ItemTitle>
        </ItemContent>
        <ItemActions className="gap-0 select-none">
          <PopConfirm
            onConfirm={() => removeField?.(field.name)}
            description="This action cannot be undone."
          >
            <ButtonTooltip
              size="icon"
              type="button"
              variant="ghost"
              className="cursor-pointer"
              disabled={field.is_system_field}
              tooltip="Remove field"
              disabledTooltip="Cannot remove system field"
            >
              <Trash2 className="size-4" />
            </ButtonTooltip>
          </PopConfirm>

          <ButtonTooltip
            size="icon"
            type="button"
            variant="ghost"
            className="cursor-pointer"
            disabled={field.immutable}
            onClick={() => setFieldHidden?.(field.name, !isHidden)}
            tooltip={isHidden ? "Show field" : "Hide field"}
            disabledTooltip="Cannot show immutable field"
          >
            {field.immutable || isHidden ? (
              <Eye className="size-4" />
            ) : (
              <EyeOff className="size-4" />
            )}
          </ButtonTooltip>

          <ButtonTooltip
            size="icon"
            type="button"
            variant="ghost"
            className="cursor-pointer"
            disabled={field.is_system_field}
            onClick={() => {
              editingFieldStore.setState({ field });
            }}
            tooltip="Edit field"
            disabledTooltip="Cannot edit system field"
          >
            <Pencil className="size-4" />
          </ButtonTooltip>

          <Button
            size="icon"
            type="button"
            variant="ghost"
            className="cursor-move"
            {...listeners}
          >
            <GripVertical className="size-4" />
          </Button>
        </ItemActions>
      </Item>
    </div>
  );
};

import {
  KeyboardSensor,
  PointerSensor,
  useSensor,
  useSensors,
  type DragStartEvent,
  type DragEndEvent,
  type DragOverEvent,
} from "@dnd-kit/core";
import { arrayMove, sortableKeyboardCoordinates } from "@dnd-kit/sortable";
import { useCallback, useState } from "react";

import { useSchemaEditForm } from "../../context";

import type { SchemaViewType } from "@/components/fsui/fscommon";
import type {
  FieldDefinition,
  SchemaDefinition,
  ZoneFieldSettings,
} from "fastschema";

export type SchemaViewsConfig = SchemaDefinition["settings"]["form"]["views"];

/**
 * Custom hook for managing drag-and-drop state and logic for schema edit views.
 * Uses TanStack Form state directly instead of local state for better integration.
 */
export const useSchemaFormViewDnd = <
  TView extends SchemaViewType<Record<string, string>>,
>({
  view,
}: {
  view: TView;
}) => {
  type ZoneKeys = keyof typeof view.zones;

  const form = useSchemaEditForm();
  const views = form.getFieldValue("settings.form.views") || {};
  const [activeField, setActiveField] = useState<FieldDefinition | undefined>(
    undefined,
  );
  const items = views?.[view.id] as Record<string, ZoneFieldSettings[]>;

  const setFormViewSettings = useCallback(
    (newItems: Record<string, ZoneFieldSettings[]>) => {
      form.setFieldValue(`settings.form.views.${view.id}`, newItems);
    },
    [form, view.id],
  );

  const sensors = useSensors(
    useSensor(PointerSensor),
    useSensor(KeyboardSensor, {
      coordinateGetter: sortableKeyboardCoordinates,
    }),
  );

  /**
   * Finds which zone contains a given item ID or zone container ID.
   * Supports both item IDs and "zone-{zoneKey}" container IDs.
   */
  const findContainer = useCallback(
    (id: string): ZoneKeys | undefined => {
      // Direct zone match
      if (id in items) return id as ZoneKeys;

      // Check for "zone-zoneKey" pattern
      if (id.startsWith("zone-")) {
        const zoneKey = id.slice(5) as ZoneKeys;
        if (zoneKey in items) return zoneKey;
      }

      // Find zone containing this item (comparing against item.field)
      return Object.keys(items).find((key) =>
        items[key as ZoneKeys].some((item) => item.field === id),
      ) as ZoneKeys | undefined;
    },
    [items],
  );

  /**
   * Finds the index of an item in a zone by field name
   */
  const findItemIndex = useCallback(
    (zoneItems: ZoneFieldSettings[], fieldName: string): number => {
      return zoneItems.findIndex((item) => item.field === fieldName);
    },
    [],
  );

  const onDragStart = useCallback((event: DragStartEvent) => {
    setActiveField(
      (event.active.data.current as unknown as { field: FieldDefinition })
        .field as FieldDefinition,
    );
  }, []);

  const onDragOver = useCallback(
    (event: DragOverEvent) => {
      const { active, over } = event;
      if (!over || active.id in items) return;

      const activeContainer = findContainer(active.id as string);
      const overContainer = findContainer(over.id as string);

      if (
        !activeContainer ||
        !overContainer ||
        activeContainer === overContainer
      ) {
        return;
      }

      // Move item between zones - update form state directly
      const activeItems = items[activeContainer];
      const overItems = items[overContainer];
      const activeIndex = findItemIndex(activeItems, active.id as string);
      const activeItem = activeItems[activeIndex];

      if (!activeItem) return;

      // Determine insertion index
      let newIndex: number;
      if (over.id in items || String(over.id).startsWith("zone-")) {
        // Dropping into empty zone
        newIndex = overItems.length;
      } else {
        const overIndex = findItemIndex(overItems, over.id as string);
        const isBelowOverItem =
          active.rect.current.translated &&
          active.rect.current.translated.top > over.rect.top + over.rect.height;
        newIndex = overIndex + (isBelowOverItem ? 1 : 0);
      }

      const newItems = {
        ...items,
        [activeContainer]: activeItems.filter(
          (item) => item.field !== active.id,
        ),
        [overContainer]: [
          ...overItems.slice(0, newIndex),
          activeItem,
          ...overItems.slice(newIndex),
        ],
      };
      setFormViewSettings(newItems);
    },
    [items, findContainer, findItemIndex, setFormViewSettings],
  );

  const onDragEnd = useCallback(
    (event: DragEndEvent) => {
      if (!event.over) {
        setActiveField(undefined);
        return;
      }

      const activeContainer = findContainer(event.active.id as string);
      const overContainer = findContainer(event.over.id as string);

      if (!activeContainer || !overContainer) {
        setActiveField(undefined);
        return;
      }

      // Reorder within same zone
      if (activeContainer === overContainer) {
        const activeIndex = findItemIndex(
          items[activeContainer],
          event.active.id as string,
        );
        const overIndex = findItemIndex(
          items[overContainer],
          event.over.id as string,
        );

        if (activeIndex !== overIndex) {
          const newItems = {
            ...items,
            [overContainer]: arrayMove(
              items[overContainer],
              activeIndex,
              overIndex,
            ),
          };

          setFormViewSettings(newItems);
        }
      }

      setActiveField(undefined);
    },
    [items, findContainer, findItemIndex, setFormViewSettings],
  );

  return {
    sensors,
    items,
    activeField,
    onDragStart,
    onDragOver,
    onDragEnd,
  };
};

import { useEffect, useState } from "react";

import {
  populateActiveFormViewSettings,
  schemaContentViews,
} from "@/components/fsui/fscommon";

import { useSchemaEditForm } from "../../context";

import { SchemaFormViewDnd } from "./dnd";

export const SchemaFormViewSettings = ({
  activeView,
}: {
  activeView?: string | null;
}) => {
  const [initialized, setInitialized] = useState(false);
  const form = useSchemaEditForm();
  const view =
    schemaContentViews.find((v) => v.id === activeView) ||
    schemaContentViews[0];

  useEffect(() => {
    const values = form.state.values;
    const { zones, needsUpdate } = populateActiveFormViewSettings(values);

    if (needsUpdate) {
      form.setFieldValue(`settings.form.views.${view.id}`, zones);
    }
    setInitialized(true);
  }, [view, form]);

  if (!initialized) {
    return null;
  }

  return (
    <SchemaFormViewDnd
      key={`${activeView}-${view.id}`}
      view={view}
    />
  );
};

import {
  SortableContext,
  verticalListSortingStrategy,
} from "@dnd-kit/sortable";
import { useStore } from "@tanstack/react-form";
import { fieldDefaultValues } from "fastschema";
import { Plus } from "lucide-react";
import { Fragment } from "react/jsx-runtime";

import { Button } from "@/components/ui/button";

import { Droppable, FieldPlaceholder } from "../../common";
import { useSchemaEditForm } from "../../context";
import { editingFieldStore } from "../../store";

import { SchemaFormFieldHandle } from "./field-handle";

import type { SchemaViewType } from "@/components/fsui/fscommon";
import type { ZoneFieldSettings } from "fastschema";

const hiddenFieldsKey = "settings.form.hidden_fields" as const;
const viewsKey = "settings.form.views" as const;
export const SchemaEditZone = <
  TView extends SchemaViewType<Record<string, string>>,
>({
  zoneId,
  view,
}: {
  zoneId: string;
  view: TView;
}) => {
  const form = useSchemaEditForm();

  const { items, fields, hiddenFields } = useStore(form.store, (state) => ({
    items: (state.values?.settings?.form?.views?.[view.id]?.[zoneId] ||
      []) as ZoneFieldSettings[],
    fields: state.values.fields,
    hiddenFields: state.values?.settings?.form?.hidden_fields || [],
  }));

  // Extract field names for SortableContext (needs string IDs)
  const sortableIds = items.map((item) => item.field);

  const setFieldHidden = (fieldName: string, hidden: boolean) => {
    const currentHidden = form.getFieldValue(hiddenFieldsKey) || [];
    const newHiddenFields = hidden
      ? Array.from(new Set([...currentHidden, fieldName]))
      : currentHidden.filter((f: string) => f !== fieldName);
    form.setFieldValue(hiddenFieldsKey, newHiddenFields);
  };

  const removeField = (fieldName: string) => {
    const currentFields = form.getFieldValue("fields") || [];
    const nextFields = currentFields.filter((f) => f.name !== fieldName);
    form.setFieldValue("fields", nextFields);

    const allViews = form.getFieldValue(viewsKey) || {};
    const newViews: typeof allViews = {};
    for (const [viewId, viewZones] of Object.entries(allViews)) {
      newViews[viewId] = {};
      for (const [zId, zoneItems] of Object.entries(
        viewZones as Record<string, ZoneFieldSettings[]>,
      )) {
        newViews[viewId][zId] = zoneItems.filter(
          (item) => item.field !== fieldName,
        );
      }
    }
    form.setFieldValue(viewsKey, newViews);
  };

  return (
    <Droppable
      key={zoneId}
      id={`zone-${zoneId}`}
    >
      <SortableContext
        id={`zone-${zoneId}`}
        items={sortableIds}
        strategy={verticalListSortingStrategy}
      >
        <div className="bg-sidebar w-full rounded-lg border border-dashed p-6">
          <div className="mb-4 flex items-center justify-between">
            <h2 className="text-xl font-semibold">{view.zones[zoneId]}</h2>
            <Button
              type="button"
              size="icon"
              variant="outline"
              title="Add field to this zone"
              className="cursor-pointer"
              onClick={() => {
                editingFieldStore.setState({
                  zoneId,
                  field: fieldDefaultValues,
                });
              }}
            >
              <Plus className="size-4" />
            </Button>
          </div>
          <div className="flex min-h-[100px] flex-col gap-4">
            {items.map((item) => {
              const fieldName = item.field;
              const fieldIndex = fields?.findIndex((f) => f.name === fieldName);
              const field = fields[fieldIndex];
              if (!field) {
                return (
                  <FieldPlaceholder
                    key={fieldName}
                    id={fieldName}
                    isError
                  />
                );
              }

              return (
                <Fragment key={fieldName}>
                  <form.Field
                    name={`fields[${fieldIndex}]`}
                    children={() => null}
                  />
                  <SchemaFormFieldHandle
                    field={field}
                    zoneFieldSettings={item}
                    hiddenFields={hiddenFields}
                    setFieldHidden={setFieldHidden}
                    removeField={removeField}
                  />
                </Fragment>
              );
            })}
          </div>
        </div>
      </SortableContext>
    </Droppable>
  );
};

import { Fragment, useState } from "react";

import { Field, FieldError } from "@/components/ui/field";

import { useSchemaEditForm } from "../context";
import { SchemaEditField } from "../field";
import { SchemaFormViewSelector } from "../view-settings/form-view-selector";
import { SchemaListViewSelector } from "../view-settings/list-view-selector";

import { SchemaFormViewSettings } from "./form";
import { SchemaListViewSettings } from "./list";

import type { SchemaDefinition } from "fastschema";

export const SchemaEditContent = ({
  schemaDefinition: _schemaDefinition,
}: {
  schemaDefinition: SchemaDefinition;
}) => {
  const form = useSchemaEditForm();
  const [mode, setMode] = useState<"form" | "list">("form");

  return (
    <Fragment>
      <div className="mb-6 flex flex-col gap-5 sm:flex-row sm:gap-5">
        <SchemaFormViewSelector
          active={mode === "form"}
          onClick={() => setMode("form")}
        />
        <SchemaListViewSelector
          active={mode === "list"}
          onClick={() => setMode("list")}
        />
      </div>
      {/* Mount the fields array so that its onChange listeners are active */}
      <form.Field
        name="fields"
        mode="array"
        children={(f) => {
          const isInvalid = !f.state.meta.isValid;
          return (
            isInvalid && (
              <Field
                data-invalid={isInvalid}
                className="mb-5"
              >
                <FieldError errors={f.state.meta.errors} />
              </Field>
            )
          );
        }}
      />

      {mode === "form" && (
        <form.Subscribe
          selector={(state) => ({
            activeView: state.values?.settings?.form?.active_view,
          })}
          children={(selected) => (
            <Fragment key={selected?.activeView}>
              {/** Mount the selected view settings field so that its onChange listeners are active */}
              <form.Field name={`settings.form.views.${selected?.activeView}`}>
                {() => null}
              </form.Field>
              <SchemaFormViewSettings
                key={selected?.activeView}
                activeView={selected?.activeView}
              />
            </Fragment>
          )}
        />
      )}
      {mode === "list" && (
        <form.Subscribe
          selector={(state) => ({
            activeView: state.values?.settings?.list?.active_view,
          })}
          children={(selected) => (
            <Fragment key={selected?.activeView}>
              {/** Mount the selected view settings field so that its onChange listeners are active */}
              <form.Field name={`settings.list.views.${selected?.activeView}`}>
                {() => null}
              </form.Field>
              <SchemaListViewSettings
                key={selected?.activeView}
                activeView={selected?.activeView}
              />
            </Fragment>
          )}
        />
      )}

      <SchemaEditField schemaForm={form} />
    </Fragment>
  );
};

import { Plus } from "lucide-react";

import { Button } from "@/components/ui/button";
import {
  Item,
  ItemActions,
  ItemContent,
  ItemMedia,
  ItemTitle,
} from "@/components/ui/item";
import {
  Tooltip,
  TooltipContent,
  TooltipTrigger,
} from "@/components/ui/tooltip";
