  return (
    <div>
      <Item
        variant="outline"
        size="sm"
        className={cn("border-0 bg-white p-2")}
        style={{
          boxShadow:
            "0 0 #0000, 0 0 #0000, 0px 2px 4px 0px rgba(0, 0, 0, 0.14), 0px 0px 2px 0px rgba(0, 0, 0, 0.12)",
        }}
      >
        <ItemMedia className="pl-1">
          <Tooltip>
            <TooltipTrigger>
              <Icon className="size-5" />
            </TooltipTrigger>
            <TooltipContent>
              <p>{field.type}</p>
            </TooltipContent>
          </Tooltip>
        </ItemMedia>
        <ItemContent>
          <ItemTitle>{field.label}</ItemTitle>
        </ItemContent>
        <ItemActions className="gap-0 select-none">
          <Button
            size="icon"
            type="button"
            variant="ghost"
            className="cursor-pointer"
            onClick={onShow}
          >
            <Plus className="size-4" />
          </Button>
        </ItemActions>
      </Item>
    </div>
  );
};

import { Pencil } from "lucide-react";

import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import {
  Popover,
  PopoverContent,
  PopoverTrigger,
} from "@/components/ui/popover";
import { Switch } from "@/components/ui/switch";

import type { FieldDefinition, SchemaDefinition } from "fastschema";

type ListViewFieldSettings =
  SchemaDefinition["settings"]["list"]["views"][string][number];

export const ListFieldSettings = ({
  field,
  settings,
  onSettingsChange,
}: {
  field: FieldDefinition;
  settings?: ListViewFieldSettings;
  onSettingsChange?: (settings: Omit<ListViewFieldSettings, "field">) => void;
}) => {
  return (
    <Popover>
      <PopoverTrigger asChild>
        <Button
          size="icon"
          type="button"
          variant="ghost"
          className="cursor-pointer"
        >
          <Pencil className="size-4" />
        </Button>
      </PopoverTrigger>
      <PopoverContent
        className="w-64"
        align="end"
      >
        <div className="grid gap-4">
          <div className="space-y-2">
            <h4 className="leading-none font-medium">
              Display Settings: {field.name}
            </h4>
            <p className="text-muted-foreground text-sm">
              Configure how field &quot;{field.name}&quot; displays in the list.
            </p>
          </div>
          <div className="grid gap-3">
            <div className="flex items-center justify-between">
              <Label htmlFor={`sortable-${field.name}`}>Sortable</Label>
              <Switch
                id={`sortable-${field.name}`}
                className="cursor-pointer"
                checked={settings?.sortable ?? false}
                onCheckedChange={(checked) =>
                  onSettingsChange?.({ sortable: checked })
                }
              />
            </div>
            <div className="flex items-center justify-between">
              <Label htmlFor={`filterable-${field.name}`}>Filterable</Label>
              <Switch
                id={`filterable-${field.name}`}
                className="cursor-pointer"
                checked={settings?.filterable ?? false}
                onCheckedChange={(checked) =>
                  onSettingsChange?.({ filterable: checked })
                }
              />
            </div>
            <div className="flex items-center justify-between gap-2">
              <Label htmlFor={`max-width-${field.name}`}>Max Width</Label>
              <Input
                id={`max-width-${field.name}`}
                type="number"
                placeholder="Auto"
                className="w-24"
                value={settings?.max_width ?? ""}
                onChange={(e) =>
                  onSettingsChange?.({
                    max_width: e.target.value
                      ? Number(e.target.value)
                      : undefined,
                  })
                }
              />
            </div>
          </div>
        </div>
      </PopoverContent>
    </Popover>
  );
};

import {
  KeyboardSensor,
  PointerSensor,
  useSensor,
  useSensors,
  type DragStartEvent,
  type DragEndEvent,
} from "@dnd-kit/core";
import { arrayMove, sortableKeyboardCoordinates } from "@dnd-kit/sortable";
import { useCallback, useState } from "react";

import { useSchemaEditForm } from "../../context";

import type { FieldDefinition, SchemaDefinition } from "fastschema";

type ListViewFields = SchemaDefinition["settings"]["list"]["views"][string];

/**
 * Custom hook for managing drag-and-drop state and logic for list view field ordering.
 */
export const useSchemaListViewDnd = ({
  activeView,
  viewFields,
}: {
  activeView?: string | null;
  viewFields: ListViewFields;
}) => {
  const form = useSchemaEditForm();
  const [activeField, setActiveField] = useState<FieldDefinition | undefined>(
    undefined,
  );

  const setListViewSettings = useCallback(
    (newFields: ListViewFields) => {
      if (!activeView) return;
      form.setFieldValue(`settings.list.views.${activeView}`, newFields);
    },
    [form, activeView],
  );

  const sensors = useSensors(
    useSensor(PointerSensor),
    useSensor(KeyboardSensor, {
      coordinateGetter: sortableKeyboardCoordinates,
    }),
  );

  const onDragStart = useCallback((event: DragStartEvent) => {
    const field = (
      event.active.data.current as { field: FieldDefinition } | undefined
    )?.field;
    setActiveField(field);
  }, []);

  const onDragEnd = useCallback(
    (event: DragEndEvent) => {
      const { active, over } = event;

      if (!over || active.id === over.id) {
        setActiveField(undefined);
        return;
      }

      const activeIndex = viewFields.findIndex((f) => f.field === active.id);
      const overIndex = viewFields.findIndex((f) => f.field === over.id);

      if (activeIndex === -1 || overIndex === -1) {
        setActiveField(undefined);
        return;
      }

      const reordered = arrayMove(viewFields, activeIndex, overIndex);
      setListViewSettings(reordered);
      setActiveField(undefined);
    },
    [viewFields, setListViewSettings],
  );

  return {
    sensors,
    activeField,
    onDragStart,
    onDragEnd,
  };
};

import {
  DndContext,
  closestCenter,
  DragOverlay,
  MeasuringStrategy,
} from "@dnd-kit/core";
import { restrictToParentElement } from "@dnd-kit/modifiers";
import {
  SortableContext,
  verticalListSortingStrategy,
} from "@dnd-kit/sortable";
import { useStore } from "@tanstack/react-form";
import { useCallback } from "react";

import { FieldPlaceholder } from "../../common";
import { useSchemaEditForm } from "../../context";

import { SchemaListAvailableField } from "./available-field";
import { useSchemaListViewDnd } from "./hooks";
import {
  SchemaListSelectedField,
  type ListViewFieldSettings,
} from "./selected-field";

import type { SchemaDefinition } from "fastschema";

type ListViewFields = SchemaDefinition["settings"]["list"]["views"][string];

export const SchemaListViewSettings = ({
  activeView,
}: {
  activeView?: string | null;
}) => {
  const form = useSchemaEditForm();

  const { fields, viewFields } = useStore(form.store, (state) => ({
    fields: state.values.fields,
    viewFields:
      state.values?.settings?.list?.views[activeView as string] ||
      state.values.fields.map((f) => ({
        field: f.name,
        invisible: false,
        filterable: true,
        sortable: true,
      })),
  }));

  const { sensors, activeField, onDragStart, onDragEnd } = useSchemaListViewDnd(
    {
      activeView,
      viewFields,
    },
  );

  const visibleFields = viewFields.filter((f) => !f.invisible);
  const visibleFieldNames = visibleFields.map((f) => f.field);

  const setFieldVisibility = useCallback(
    (fieldName: string, visible: boolean) => {
      if (!activeView) return;
      const listViewKey = `settings.list.views.${activeView}` as const;
      const currentView: ListViewFields = form.getFieldValue(listViewKey) || [];

      const fieldIndex = currentView.findIndex((f) => f.field === fieldName);
      if (fieldIndex === -1) {
        // Field not in view, add it
        if (visible) {
          form.setFieldValue(listViewKey, [
            ...currentView,
            { field: fieldName, sortable: true, filterable: true },
          ]);
        }
      } else {
        // Update existing field
        const updated = [...currentView];
        updated[fieldIndex] = {
          ...updated[fieldIndex],
          invisible: !visible,
        };
        form.setFieldValue(listViewKey, updated);
      }
    },
    [activeView, form],
  );

  const updateFieldSettings = useCallback(
    (fieldName: string, updates: Partial<ListViewFieldSettings>) => {
      if (!activeView) return;
      const listViewKey = `settings.list.views.${activeView}` as const;
      const currentView: ListViewFields = form.getFieldValue(listViewKey) || [];

      const fieldIndex = currentView.findIndex((f) => f.field === fieldName);
      if (fieldIndex === -1) return;

      const updated = [...currentView];
      updated[fieldIndex] = {
        ...updated[fieldIndex],
        ...updates,
      };
      form.setFieldValue(listViewKey, updated);
    },
    [activeView, form],
  );

  return (
    <div className="grid gap-3 lg:grid-cols-3 lg:gap-4">
      <div className="lg:col-span-1">
        <div className="bg-sidebar w-full rounded-lg border border-dashed p-6">
          <div className="mb-4 flex items-center justify-between">
            <h2 className="text-xl font-semibold">Available Fields</h2>
          </div>
          <div className="flex min-h-[100px] flex-col gap-4">
            {fields
              .filter((f) => !visibleFieldNames.includes(f.name))
              .map((field) => {
                return (
                  <SchemaListAvailableField
                    key={field.name}
                    field={field}
                    onShow={() => setFieldVisibility(field.name, true)}
                  />
                );
              })}
          </div>
        </div>
      </div>
      <div className="lg:col-span-2">
        <div className="bg-sidebar w-full rounded-lg border border-dashed p-6">
          <div className="mb-4 flex items-center justify-between">
            <h2 className="text-xl font-semibold">Display Fields</h2>
          </div>
          <DndContext
            sensors={sensors}
            collisionDetection={closestCenter}
            modifiers={[restrictToParentElement]}
            onDragStart={onDragStart}
            onDragEnd={onDragEnd}
            measuring={{
              droppable: {
                strategy: MeasuringStrategy.Always,
              },
            }}
          >
            <SortableContext
              items={visibleFieldNames}
              strategy={verticalListSortingStrategy}
            >
              <div className="flex min-h-[100px] flex-col gap-4">
                {visibleFields.map((viewField) => {
                  const field = fields.find((f) => f.name === viewField.field);
                  return field ? (
                    <SchemaListSelectedField
                      key={field.name}
                      field={field}
                      settings={viewField}
                      onHide={() => setFieldVisibility(field.name, false)}
                      onSettingsChange={(updates) =>
                        updateFieldSettings(field.name, updates)
                      }
                    />
                  ) : null;
                })}
              </div>
            </SortableContext>
            <DragOverlay adjustScale={false}>
              {activeField && (
                <FieldPlaceholder
                  id={activeField.name}
                  field={activeField}
                  opacity={0.9}
                />
              )}
            </DragOverlay>
          </DndContext>
        </div>
      </div>
    </div>
  );
};

