  schemaForm: UseFormReturnOnChangeType<typeof schemaDefinitionSchema>;
  fieldForm: FieldFormType;
}) => {
  const editingField = useStore(editingFieldStore, (s) => s);

  // Get field type and name from field form state directly
  const fieldType = fieldForm.store.state.values.type;

  // Get active view from schemaForm
  const activeView = useStore(
    schemaForm.store,
    (s) => s.values.settings?.form?.active_view ?? "view-right-sidebar",
  );

  // Get all zones from active view
  const allZones = useStore(
    schemaForm.store,
    (s) =>
      (s.values.settings?.form?.views?.[activeView] ?? {}) as Record<
        string,
        ZoneFieldSettings[]
      >,
  );

  // Search all zones to find the saved zone item for this field
  const savedZoneItem = (() => {
    const fieldName = editingField?.field?.name;
    if (!fieldName) return undefined;
    for (const zId in allZones) {
      if (Object.prototype.hasOwnProperty.call(allZones, zId)) {
        const items = allZones[zId] || [];
        const found = items.find((item) => item.field === fieldName);
        if (found) return found;
      }
    }
    return undefined;
  })();

  // Use pending zone field settings from store if available, otherwise use saved
  const pendingSettings = editingField?.zoneFieldSettings;

  // Merge pending with saved, pending takes precedence
  // Use 'in' operator to check if renderer was explicitly set (even to undefined)
  const currentRenderer =
    pendingSettings && "renderer" in pendingSettings
      ? pendingSettings.renderer
      : savedZoneItem?.renderer;
  const currentOptions = {
    ...savedZoneItem?.options,
    ...pendingSettings?.options,
  };

  // Get available renderers from registry
  const availableRenderers = fieldRegistry.getRenderers(fieldType);

  // Default renderer is the first one (highest priority)
  const defaultRenderer = availableRenderers[0];
  const defaultClassName = defaultRenderer?.renderer;

  // If no renderer is selected, treat as if default is selected
  const effectiveSelectedClass = currentRenderer ?? defaultClassName;

  // Get the current entry based on effective selection
  const currentEntry = fieldRegistry.getEntry(
    fieldType as string,
    effectiveSelectedClass,
  );

  // Update zone field settings in the store (deferred until save)
  const updateZoneFieldSettings = useCallback(
    (updates: Partial<ZoneFieldSettings>) => {
      const currentState = editingFieldStore.state;
      if (!currentState) return;

      editingFieldStore.setState({
        ...currentState,
        zoneFieldSettings: {
          ...currentState.zoneFieldSettings,
          ...updates,
        },
      });
    },
    [],
  );

  // Handle renderer change
  const handleRendererChange = (value: string) => {
    const isDefault = value === defaultClassName;
    const isOnlyRenderer = availableRenderers.length <= 1;

    // If selecting default renderer or there's only one renderer, clear the value
    if (isDefault || isOnlyRenderer) {
      updateZoneFieldSettings({ renderer: undefined, options: undefined });
    } else {
      updateZoneFieldSettings({ renderer: value });
    }
  };

  // Handle settings change
  const handleSettingChange = (name: string, value: unknown) => {
    const newOptions = {
      ...currentOptions,
      [name]: value,
    };
    updateZoneFieldSettings({ options: newOptions });
  };

  return (
    <FieldSet>
      <FieldLegend>Renderer Settings</FieldLegend>
      <FieldDescription>
        Configure how this field is rendered in content forms.
      </FieldDescription>
      <FieldGroup>
        {/* Renderer class selector */}
        <Field>
          <FieldLabel>Renderer</FieldLabel>
          <Select
            value={effectiveSelectedClass ?? ""}
            onValueChange={handleRendererChange}
            disabled={availableRenderers.length <= 1}
          >
            <SelectTrigger className="w-full">
              <SelectValue placeholder="Select renderer..." />
            </SelectTrigger>
            <SelectContent>
              {availableRenderers.map((r) => (
                <SelectItem
                  key={r.renderer}
                  value={r.renderer ?? ""}
                >
                  {r.label ?? r.renderer}
                  {r.renderer === defaultClassName && " (default)"}
                </SelectItem>
              ))}
            </SelectContent>
          </Select>
          {availableRenderers.length <= 1 && (
            <p className="text-muted-foreground mt-1 text-xs">
              Only one renderer available for this field type.
            </p>
          )}
        </Field>

        {/* Dynamic settings fields from selected renderer */}
        {currentEntry?.settingsFields && (
          <Fragment>
            {currentEntry.settingsFields.map((settingDef) => (
              <FieldRenderer
                key={settingDef.name}
                fieldDef={settingDef}
                value={currentOptions[settingDef.name]}
                onChange={(val) => handleSettingChange(settingDef.name, val)}
              />
            ))}
          </Fragment>
        )}

        {availableRenderers.length === 0 && (
          <p className="text-muted-foreground text-sm">
            No custom renderers available for {fieldType as FieldType} fields.
          </p>
        )}
      </FieldGroup>
    </FieldSet>
  );
};

import {
  closestCenter,
  DndContext,
  KeyboardSensor,
  PointerSensor,
  useSensor,
  useSensors,
  type DragEndEvent,
} from "@dnd-kit/core";
import { restrictToParentElement } from "@dnd-kit/modifiers";
import {
  arrayMove,
  SortableContext,
  sortableKeyboardCoordinates,
  verticalListSortingStrategy,
} from "@dnd-kit/sortable";
import { useStore } from "@tanstack/react-form";

import { SortableEnumItem } from "./item";

import type { UseFormReturnOnChangeType } from "@/components/fsui/fsform/fsform";
import type { fieldDefinitionSchema } from "fastschema";

export const generateId = () =>
  `enum-${Date.now()}-${Math.random().toString(36).substring(2, 9)}`;

export const EnumsDnd = ({
  form,
}: {
  form: UseFormReturnOnChangeType<typeof fieldDefinitionSchema>;
}) => {
  const enums = useStore(form.store, (state) => state.values.enums) || [];
  const itemsWithIds = (enums || []).map((item) => {
    if (!item.id) {
      const newId = generateId();
      const updatedItems = (enums || []).map((i) =>
        i === item ? { ...i, id: newId } : i,
      );
      // Use queueMicrotask to avoid updating during render
      queueMicrotask(() => form.setFieldValue("enums", updatedItems));
      return { ...item, id: newId };
    }
    return item;
  });
  const sensors = useSensors(
    useSensor(PointerSensor, {
      activationConstraint: {
        distance: 2,
      },
    }),
    useSensor(KeyboardSensor, {
      coordinateGetter: sortableKeyboardCoordinates,
    }),
  );

  const handleDragEnd = (event: DragEndEvent) => {
    const { active, over } = event;

    if (active.id !== over?.id && over?.id) {
      const itemIds = enums.map((item) => item.id);
      const oldIndex = itemIds.indexOf(active?.id as string);
      const newIndex = itemIds.indexOf(over?.id as string);

      if (oldIndex !== -1 && newIndex !== -1) {
        const newItems = arrayMove(enums, oldIndex, newIndex);
        form.setFieldValue("enums", newItems);
      }
    }
  };

  return (
    <DndContext
      sensors={sensors}
      collisionDetection={closestCenter}
      modifiers={[restrictToParentElement]}
      onDragEnd={handleDragEnd}
    >
      <SortableContext
        items={itemsWithIds.map((item) => item.id as string)}
        strategy={verticalListSortingStrategy}
      >
        {itemsWithIds.map((item, i) => {
          return (
            <SortableEnumItem
              key={item.id}
              form={form}
              item={item}
              index={i}
            />
          );
        })}
      </SortableContext>
    </DndContext>
  );
};

