const RELATION_TYPE_MAP: Record<
  string,
  {
    type: FieldRelation["type"];
    owner?: boolean;
  }
> = {
  o2o_owner: { type: "o2o", owner: true },
  o2o_non_owner: { type: "o2o", owner: false },
  o2m_owner: { type: "o2m", owner: true },
  o2m_non_owner: { type: "o2m", owner: false },
  m2m: { type: "m2m", owner: undefined },
};

export const getCompositeKey = (
  type?: FieldRelation["type"],
  owner?: boolean,
): string => {
  if (!type) return "o2o_owner";

  // M2M relations don't have an owner concept, so return "m2m" directly
  if (type === "m2m") return "m2m";

  for (const [key, value] of Object.entries(RELATION_TYPE_MAP)) {
    if (value.type === type && value.owner === owner) {
      return key;
    }
  }

  return "o2o_owner";
};

export const parseCompositeKey = (
  key: string,
): { type: FieldRelation["type"]; owner?: boolean } => {
  return RELATION_TYPE_MAP[key] || { type: "o2o", owner: true };
};

export const RelationTypeSelector = ({
  form,
}: {
  form: UseFormReturnOnChangeType<typeof fieldDefinitionSchema>;
}) => {
  return (
    <form.Field
