import { useCallback } from "react";
import { toast } from "sonner";

import { mapEntries, insertBefore } from "@/components/fsui/fscommon";

import { editingFieldStore, type EditingFieldState } from "../store";

import type { UseFormReturnOnChangeType } from "@/components/fsui/fsform/fsform";
import type {
  FieldDefinition,
  SchemaDefinition,
  schemaDefinitionSchema,
  ZoneFieldSettings,
} from "fastschema";

type SchemaForm = UseFormReturnOnChangeType<typeof schemaDefinitionSchema>;
type FormViews = SchemaDefinition["settings"]["form"]["views"];
type ListViews = SchemaDefinition["settings"]["list"]["views"];
type ListFieldSettings = ListViews[string][number];

interface SaveFieldParams {
  field: FieldDefinition;
  editingField?: EditingFieldState;
  schemaForm: SchemaForm;
}

/**
 * Renames a field in all form view zones (updates item.field).
 */
const renameInFormViews = (
  views: FormViews,
  oldName: string,
  newName: string,
): FormViews =>
  mapEntries(views, (viewId, zones) => [
    viewId,
    mapEntries(zones || {}, (zoneId, items) => [
      zoneId,
      (items || []).map((item) =>
        item.field === oldName ? { ...item, field: newName } : item,
      ),
    ]),
  ]);

/**
 * Renames a field in all list views while preserving order.
 */
const renameInListViews = (
  views: ListViews,
  oldName: string,
  newName: string,
): ListViews =>
  mapEntries(views, (viewId, fields) => [
    viewId,
    (fields || []).map((f) =>
      f.field === oldName ? { ...f, field: newName } : f,
    ),
  ]);

const updateField = ({ field, editingField, schemaForm }: SaveFieldParams) => {
  const identifier =
    editingField?.field?.server_name ||
    editingField?.field?.name ||
    field.server_name ||
    "";

  const fields = schemaForm.getFieldValue("fields") || [];
  const fieldIndex = fields.findIndex((f) =>
    [f.server_name, f.name].filter(Boolean).includes(identifier),
  );

  if (fieldIndex === -1) {
    toast.error(`Original field "${field.name}" not found.`);
    return;
  }

  const oldName = editingField?.field?.name || identifier;
  const newName = field.name;
  const isRenamed = oldName && newName && oldName !== newName;

  if (isRenamed) {
    const formViews = schemaForm.getFieldValue("settings.form.views") || {};
    const listViews = schemaForm.getFieldValue("settings.list.views") || {};

    schemaForm.setFieldValue(
      "settings.form.views",
      renameInFormViews(formViews, oldName, newName),
    );
    schemaForm.setFieldValue(
      "settings.list.views",
      renameInListViews(listViews, oldName, newName),
    );

    // Update primary_field and label_field if they reference the renamed field
    const primaryField = schemaForm.getFieldValue("primary_field");
    const labelField = schemaForm.getFieldValue("label_field");

    if (primaryField === oldName) {
      schemaForm.setFieldValue("primary_field", newName);
    }
    if (labelField === oldName) {
      schemaForm.setFieldValue("label_field", newName);
    }
  }

  // Apply pending zone field settings (renderer/options) if any
  const pendingSettings = editingField?.zoneFieldSettings;
  // Check if renderer key exists (even if undefined) using 'in' operator
  const hasRendererChange = pendingSettings && "renderer" in pendingSettings;
  const hasOptionsChange = pendingSettings?.options !== undefined;
  if (hasRendererChange || hasOptionsChange) {
    const formActiveView = schemaForm.getFieldValue(
      "settings.form.active_view",
    );
    const targetZoneId = editingField?.zoneId ?? "main";
    if (formActiveView) {
      const formViewKey = `settings.form.views.${formActiveView}` as const;
      const zones = schemaForm.getFieldValue(formViewKey) || {};
      const fieldName = isRenamed ? newName : oldName;
      const newZoneItem: ZoneFieldSettings = {
        field: fieldName,
        ...(hasOptionsChange && { options: pendingSettings.options }),
      };

      // Search all zones to find if the field already exists
      let foundInZone: string | null = null;
      let foundIndex = -1;
      for (const zId in zones) {
        if (Object.prototype.hasOwnProperty.call(zones, zId)) {
          const items: ZoneFieldSettings[] = zones[zId] || [];
          const idx = items.findIndex((item) => item.field === fieldName);
          if (idx !== -1) {
            foundInZone = zId;
            foundIndex = idx;
            break;
          }
        }
      }

      if (foundInZone !== null && foundIndex !== -1) {
        // Update existing zone item in its current zone
        const existingItem = zones[foundInZone][foundIndex];
        const updatedItem = {
          ...existingItem,
          ...newZoneItem,
        };
        // Handle renderer: if explicitly set (even to undefined), update it
        if (hasRendererChange) {
          if (pendingSettings.renderer === undefined) {
            // User selected default renderer - remove the renderer key
            delete updatedItem.renderer;
          } else {
            updatedItem.renderer = pendingSettings.renderer;
          }
        }
        zones[foundInZone][foundIndex] = updatedItem;
      } else {
        // Add new zone item to the target zone
        const zoneItems: ZoneFieldSettings[] = zones[targetZoneId] || [];
        // Only include renderer if it's not the default (undefined)
        if (hasRendererChange && pendingSettings.renderer !== undefined) {
          newZoneItem.renderer = pendingSettings.renderer;
        }
        zoneItems.push(newZoneItem);
        zones[targetZoneId] = zoneItems;
      }
      schemaForm.setFieldValue(formViewKey, zones);
    }
  }

  schemaForm.setFieldValue(`fields[${fieldIndex}]`, field);
  editingFieldStore.setState(undefined);
};

const addField = ({ field, editingField, schemaForm }: SaveFieldParams) => {
  const formActiveView = schemaForm.getFieldValue("settings.form.active_view");
  const listActiveView = schemaForm.getFieldValue("settings.list.active_view");
  const zoneId = editingField?.zoneId ?? "main";

  const isCreatedAt = (f: FieldDefinition) => f.name === "created_at";

  // Add to fields array (before created_at)
  const fields = schemaForm.getFieldValue("fields") ?? [];
  schemaForm.setFieldValue("fields", insertBefore(fields, field, isCreatedAt));

  // Add to active form view zone (before created_at)
  if (formActiveView) {
    const formViewKey = `settings.form.views.${formActiveView}` as const;
    const zones = schemaForm.getFieldValue(formViewKey) || {};
    const zoneItems: ZoneFieldSettings[] = zones[zoneId] || [];
    // Include pending zone field settings (renderer/options) if any
    const pendingSettings = editingField?.zoneFieldSettings;
    const newZoneItem: ZoneFieldSettings = {
      field: field.name,
      ...(pendingSettings?.renderer && { renderer: pendingSettings.renderer }),
      ...(pendingSettings?.options && { options: pendingSettings.options }),
    };
    zones[zoneId] = insertBefore(
      zoneItems,
      newZoneItem,
      (item) => item.field === "created_at",
    );
    schemaForm.setFieldValue(formViewKey, zones);
  }

  // Add to active list view (before created_at)
  if (field.name && listActiveView) {
    const listViewKey = `settings.list.views.${listActiveView}` as const;
    const listView = schemaForm.getFieldValue(listViewKey) || [];
    const newEntry: ListFieldSettings = {
      field: field.name,
      sortable: true,
      filterable: true,
    };

    const updatedList = insertBefore(
      listView,
      newEntry,
      (f) => f.field === "created_at",
    );

    schemaForm.setFieldValue(listViewKey, updatedList);
  }

  editingFieldStore.setState(undefined);
};

export const useSaveField = ({
  editingField,
  schemaForm,
}: {
  editingField?: EditingFieldState;
  schemaForm: SchemaForm;
}) =>
  useCallback(
    (field: FieldDefinition) => {
      const isExistingField = Boolean(
        editingField?.field?.server_name ||
          editingField?.field?.name ||
          field.server_name,
      );

      const params: SaveFieldParams = { field, editingField, schemaForm };

      if (isExistingField) {
        updateField(params);
      } else {
        addField(params);
      }
    },
    [editingField, schemaForm],
  );

