}: {
  schemaForm: UseFormReturnOnChangeType<typeof schemaDefinitionSchema>;
}) => {
  const editingField = useStore(editingFieldStore, (s) => s);

  const saveField = useSaveField({ editingField, schemaForm });
  const form = useForm({
    onSubmit: ({ value }) => {
      try {
        saveField(value);
      } catch (error) {
        logger.error("Failed to update field", error);
      }
    },
    defaultValues: editingField?.field ?? fieldDefaultValues,
    validators: {
      onChange: fieldDefinitionSchema,
