  });

  useEffect(() => {
    form.reset(editingField?.field ?? fieldDefaultValues);
  }, [form, editingField?.field]);

  if (!editingField?.field) {
    return null;
  }

  return (
    <TabDialog
      open={!!editingField?.field}
      onOpenChange={(isOpen) => {
        if (!isOpen) {
          editingFieldStore.setState(undefined);
