        right: (
          <Button
            type="button"
            size="sm"
            className="cursor-pointer"
            onClick={() => {
              const fieldNameValue = form.getFieldValue("name");
              if (!fieldNameValue?.trim()) {
                toast.error("Field name is required.");
                return;
