/**
 * Cleans up settings by removing references to non-existing fields.
 * This ensures form/list view settings only contain fields that exist in the schema.
 */
const cleanupSchemaSettings = (
  definition: SchemaDefinition,
): SchemaDefinition => {
  const existingFieldNames = new Set(definition.fields.map((f) => f.name));

  // Clean up form view settings - remove zone items for non-existing fields
  if (definition.settings?.form?.views) {
    definition.settings.form.views = mapEntries(
      definition.settings.form.views,
      (viewId, zones) => [
        viewId,
        mapEntries(zones || {}, (zoneId, items) => [
          zoneId,
          ((items || []) as ZoneFieldSettings[]).filter((item) =>
            existingFieldNames.has(item.field),
          ),
        ]),
      ],
    );
  }

  // Clean up list view settings - remove entries for non-existing fields
  if (definition.settings?.list?.views) {
    definition.settings.list.views = mapEntries(
      definition.settings.list.views,
      (viewId, fields) => [
        viewId,
        (fields || []).filter((f) => existingFieldNames.has(f.field)),
      ],
    );
  }

  return definition;
};

export const SchemaEditPage = ({
  initialDefinition,
  getSchemas,
  onValuesChange,
  onSaved,
}: {
  initialDefinition: SchemaDefinition;
  getSchemas: () => SchemaDefinition[];
  onValuesChange?: (props: {
    values: SchemaDefinition;
    hasChanges?: boolean;
  }) => void;
  onSaved?: (props: { definition: SchemaDefinition; schema: Schema }) => void;
}) => {
  const { fastschema } = useFastSchema();
  const onSubmit = async ({
    value: rawDefinition,
  }: {
    value: SchemaDefinition;
  }) => {
    const definition = cleanupSchemaSettings(rawDefinition);
    const rename_fields: RenameItem[] = definition.fields
      .filter((f) => f.server_name && f.name !== f.server_name)
      .map((f) => ({ from: f.server_name as string, to: f.name }));

    try {
      const schema = initialDefinition.name
        ? await fastschema.schemas().update(initialDefinition.name, {
            schema: definition,
            rename_fields,
          })
        : await fastschema.schemas().create(definition);
      onSaved?.({ definition, schema });
    } catch (error) {
      logger.error("Failed to save schema", error);
      toast.error("Failed to save schema: " + (error as Error).message);
    }
  };

  initialDefinition = cleanupSchemaSettings(
    ensureSchemaDefinition(initialDefinition),
  );
  const form = useForm({
    onSubmit,
    defaultValues: initialDefinition,
    validators: { onChange: schemaDefinitionSchema },
    listeners: {
      onChange: (state) => {
        onValuesChange?.({
          values: state.formApi.store.state.values,
          hasChanges: !deepEqual(
            initialDefinition,
            state.formApi.store.state.values,
          ),
        });
      },
    },
  });

  return (
    <SchemaEditContext.Provider
      value={{ form, schemaDefinition: initialDefinition, getSchemas }}
    >
      <form
        onSubmit={(e) => {
          e.preventDefault();
          form.handleSubmit();
        }}
      >
        <Card className="border-0 p-0 px-1 pt-0 shadow-none">
          <CardHeader className="mt-0 space-y-0 border-b p-0 [.border-b]:pb-3">
            <SchemaEditHeader schemaDefinition={initialDefinition} />
          </CardHeader>
          <CardContent className="p-0">
            <SchemaEditContent schemaDefinition={initialDefinition} />
          </CardContent>
        </Card>
      </form>
    </SchemaEditContext.Provider>
  );
};

