export const SchemaListViewSelector = ({
  active,
  onClick,
}: {
  active?: boolean;
  onClick?: () => void;
}) => {
  const form = useSchemaEditForm();
  const inputRef = useRef<HTMLInputElement>(null);
  const { views, activeView } = useStore(form.store, (state) => ({
    views:
      state.values?.settings?.list?.views ||
      schemaDefinitionDefaultValues.settings.list.views,
    activeView:
      state.values?.settings?.list?.active_view ??
      schemaDefinitionDefaultValues.settings.list.active_view,
  }));
  const [open, setOpen] = useState(false);
  const [editingView, setEditingView] = useState<string>();

  const setActiveView = (viewName: string) => {
    if (viewName) {
      form.setFieldValue("settings.list.active_view", viewName);
    }
  };

  const saveView = () => {
    if (!inputRef.current?.value) {
      return;
    }

    const inputValue = inputRef.current.value;
    let updatedViews = { ...views };

    if (activeView === editingView) {
      const clonedValues = [...(views[activeView] || [])];
      const { [activeView]: _, ...remainingViews } = views;
      updatedViews = { ...remainingViews, [inputValue]: clonedValues };
    } else {
      updatedViews = { ...views, [inputValue]: [] };
    }

    form.setFieldValue("settings.list.views", updatedViews);
    setActiveView(inputValue);
    setEditingView("");
    setOpen(false);
  };

  const deleteView = (viewName: string) => {
    if (!viewName || !views[viewName]) {
      return;
    }

    if (Object.keys(views).length < 2) {
      toast.error("There must be at least one list view.");
      return;
    }

    const { [viewName]: _, ...remainingViews } = views;
    form.setFieldValue("settings.list.views", remainingViews);

    if (activeView === viewName) {
      const nextActiveView = Object.keys(remainingViews)[0] ?? "";
      setActiveView(nextActiveView);
    }
  };

  return (
    <div className="flex flex-row items-center justify-between">
      <form.Field
        name="settings.list.views"
        children={() => {
          return null;
        }}
      />
      <form.Field
        name="settings.list.active_view"
        children={(field) => {
          const isInvalid =
            field.state.meta.isTouched && !field.state.meta.isValid;
          return (
            <Field data-invalid={isInvalid}>
              <ButtonGroup>
                <Button
                  variant={active ? "secondary" : "outline"}
                  className={cn("cursor-pointer", active && "border")}
                  type="button"
                  onClick={onClick}
                >
                  <ListCheck />
                  List view
                </Button>
                <Select
                  name="active-list-view"
                  onValueChange={setActiveView}
                  value={field.state.value ?? ""}
                  defaultValue={field.state.value ?? ""}
                  disabled={!active}
                >
                  <SelectTrigger className="w-[150px] cursor-pointer">
                    <SelectValue placeholder="Select a list view" />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectGroup>
                      {Object.keys(views).map((viewName) => (
                        <SelectItem
                          key={viewName}
                          className="cursor-pointer"
                          value={viewName}
                        >
                          {viewName}
                        </SelectItem>
                      ))}
                    </SelectGroup>
                  </SelectContent>
                </Select>
                <Button
                  variant="outline"
                  size="icon"
                  className={cn("cursor-pointer", active && "border")}
                  type="button"
                  disabled={!activeView || !active}
                  onClick={() => {
                    setEditingView(activeView);
                    setOpen(true);
                  }}
                >
                  <Pencil />
                </Button>
                <PopConfirm onConfirm={() => deleteView(activeView ?? "")}>
                  <Button
                    variant="outline"
                    size="icon"
                    className={cn("cursor-pointer", active && "border")}
                    type="button"
                    disabled={
                      Object.keys(views).length < 2 || !activeView || !active
                    }
                  >
                    <Trash2 />
                  </Button>
                </PopConfirm>
                <Popover
                  open={open}
                  onOpenChange={setOpen}
                >
                  <PopoverTrigger asChild>
                    <Button
                      variant="outline"
                      size="icon"
                      className={cn("cursor-pointer", active && "border")}
                      disabled={!active}
                      type="button"
                      onClick={() => {
                        setActiveView("");
                      }}
                    >
                      <Plus />
                    </Button>
                  </PopoverTrigger>
                  <PopoverContent
                    align="end"
                    className="rounded-xl p-0 text-sm"
                  >
                    <div className="px-4 py-3">
                      <div className="text-sm font-medium">List View</div>
                    </div>
                    <Separator />
                    <div className="p-4 text-sm *:[p:not(:last-child)]:mb-2">
                      <Input
                        name="list-view-name"
                        placeholder="View Name"
                        className="mb-4 resize-none"
                        ref={inputRef}
                        defaultValue={editingView}
                      />
                      <p className="text-muted-foreground">
                        List views control how records are displayed in a list
                        format.
                      </p>
                      <div className="text-right">
                        <Button
                          type="button"
                          size="sm"
                          variant="secondary"
                          className="cursor-pointer border"
                          onClick={() => {
                            setOpen(false);
                            setEditingView("");
                          }}
                        >
                          Cancel
                        </Button>
                        <Button
                          type="button"
                          size="sm"
                          className="ml-2 cursor-pointer"
                          onClick={() => saveView()}
                        >
                          Save
                        </Button>
                      </div>
                    </div>
                  </PopoverContent>
                </Popover>
                {isInvalid && <FieldError errors={field.state.meta.errors} />}
              </ButtonGroup>
            </Field>
          );
        }}
      />
    </div>
  );
};
